223→
224→export function createRailing(startPoint, endPoint, options = {}) {
225→  return {
226→    id: generateId('rail'),
227→    startPoint: { x: startPoint.x, y: startPoint.y },
228→    endPoint: { x: endPoint.x, y: endPoint.y },
