66→export function sanitizeProjectPhaseReferences(project, validPhaseIds) {
67→  return {
68→    ...project,
69→    floors: (project.floors || []).map((floor) => (
70→      mapPhaseAssignableFloorObjects(floor, (obj) => (
71→        obj.phaseId == null || validPhaseIds.has(obj.phaseId)
72→          ? obj
73→          : { ...obj, phaseId: null }
74→      ))
75→    )),
76→    roofSystem: project.roofSystem?.phaseId == null || validPhaseIds.has(project.roofSystem.phaseId)
77→      ? project.roofSystem
78→      : { ...project.roofSystem, phaseId: null },
79→    trussSystems: (project.trussSystems || []).map((trussSystem) => (
80→      trussSystem.phaseId == null || validPhaseIds.has(trussSystem.phaseId)
81→        ? trussSystem
82→        : { ...trussSystem, phaseId: null }
83→    )),
84→    sheets: (project.sheets || []).map((sheet) => ({
85→      ...sheet,
86→      viewports: (sheet.viewports || []).map((viewport) => (
87→        viewport.phaseId == null || validPhaseIds.has(viewport.phaseId)
88→          ? viewport
