 637→function beginNode(builder, element) {
 638→  const localMatrix = getLocalMatrix(element);
 639→  const tagName = element.tagName.toLowerCase();
 640→  const needsClip = tagName === 'svg' && element !== getExportSvg();
 641→  const shouldWrap = needsClip || !matrixIsIdentity(localMatrix);
 642→
 643→  if (!shouldWrap) return false;
 644→
 645→  builder.write('q');
 646→  if (!matrixIsIdentity(localMatrix)) {
 647→    builder.write(`${fmt(localMatrix.a)} ${fmt(localMatrix.b)} ${fmt(localMatrix.c)} ${fmt(localMatrix.d)} ${fmt(localMatrix.e)} ${fmt(localMatrix.f)} cm`);
 648→  }
 649→
 650→  if (needsClip) {
 651→    const width = Number(element.getAttribute('width')) || 0;
 652→    const height = Number(element.getAttribute('height')) || 0;
 653→    builder.write(`0 0 ${fmt(width)} ${fmt(height)} re W n`);
 654→  }
 655→
 656→  return true;
 657→}
