418→export function normalizeTrussSystem(trussSystem = {}, project = null, catalog = getDefaultTrussTypes()) {
419→  const floorId = trussSystem?.floorId || getDefaultActiveFloorId(project, trussSystem?.floorId);
420→  const floor = project ? getProjectFloor(project, floorId) : null;
421→  const roofAttachmentId = project?.roofSystem?.trussAttachmentId === trussSystem?.id
422→    ? project.roofSystem.id
423→    : null;
424→
425→  const trussInstances = (trussSystem?.trussInstances || []).map((instance) => ({
426→    ...normalizeTrussInstance(instance, floorId, catalog),
427→    roofAttachmentId,
428→  }));
429→
430→  return {
431→    ...createTrussSystem(trussSystem?.name || 'Truss System', { floorId, catalog }),
432→    ...trussSystem,
433→    id: trussSystem?.id || generateId('truss_system'),
434→    name: trussSystem?.name || 'Truss System',
435→    floorId,
436→    phaseId: normalizePhaseId(trussSystem?.phaseId),
437→    baseElevation: isFiniteNumber(trussSystem?.baseElevation)
438→      ? trussSystem.baseElevation
439→      : (floor ? getFloorTopElevation(floor) : 0),
440→    planRotationOffsetDegrees: normalizeRotationDegrees(trussSystem?.planRotationOffsetDegrees),
441→    planOffset: clonePlanOffset(trussSystem?.planOffset),
442→    planLengthScale: normalizePlanLengthScale(trussSystem?.planLengthScale),
443→    purlinSystem: normalizePurlinSystem(trussSystem?.purlinSystem),
444→    trussInstances,
445→  };
446→}
