468→export function hasBeamSupportedTrussInstances(trussSystem) {
469→  return (trussSystem?.trussInstances || []).some((instance) => (
470→    instance.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
471→  ));
