487→function syncBeamSupportedInstance(instance, floor, catalog, roofAttachmentId) {
488→  const normalized = normalizeTrussInstance(instance, floor?.id || instance?.floorId || null, catalog);
489→  if (normalized.supportMode !== TRUSS_SUPPORT_MODES.BEAM_PAIR) {
490→    return {
491→      ...normalized,
492→      roofAttachmentId,
493→    };
494→  }
495→
496→  const derived = deriveBeamSupportedInstanceGeometry(normalized, floor);
497→  if (!derived.valid) {
498→    return null;
499→  }
500→
501→  return {
502→    ...normalized,
503→    floorId: floor?.id || normalized.floorId || null,
504→    startPoint: derived.startPoint,
505→    endPoint: derived.endPoint,
506→    count: derived.count,
507→    supportOffsetAlongAxis: derived.effectiveOffset,
508→    supportBeamIds: derived.supportBeamIds,
509→    roofAttachmentId,
510→  };
511→}
512→
513→function syncTrussSystemGeometry(trussSystem, project, catalog) {
514→  const normalizedSystem = normalizeTrussSystem(trussSystem, project, catalog);
515→  const floor = getProjectFloor(project, normalizedSystem.floorId);
516→  if (!floor) return null;
517→
518→  const roofAttachmentId = project?.roofSystem?.trussAttachmentId === normalizedSystem.id
519→    ? project.roofSystem.id
520→    : null;
521→  const syncedInstances = (normalizedSystem.trussInstances || [])
522→    .map((instance) => syncBeamSupportedInstance(instance, floor, catalog, roofAttachmentId))
523→    .filter(Boolean);
524→
525→  if (!syncedInstances.length) {
526→    return null;
527→  }
528→
529→  const beamSupportedInstance = syncedInstances.find((instance) => (
530→    instance.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
531→  )) || null;
532→  const derivedBaseElevation = beamSupportedInstance
533→    ? deriveBeamSupportedInstanceGeometry(beamSupportedInstance, floor)
534→    : null;
535→
536→  return {
537→    ...normalizedSystem,
538→    baseElevation: derivedBaseElevation?.valid
539→      ? derivedBaseElevation.baseElevation
540→      : normalizedSystem.baseElevation,
541→    trussInstances: syncedInstances,
542→  };
543→}
544→
545→export function syncProjectTrussSystems(project) {
546→  if (!project) return project;
547→
548→  const catalog = getDefaultTrussTypes();
549→  const normalizedTrussSystems = (project.trussSystems || [])
550→    .map((trussSystem) => syncTrussSystemGeometry(trussSystem, project, catalog))
551→    .filter(Boolean);
552→
553→  const validTrussIds = new Set(normalizedTrussSystems.map((entry) => entry.id));
554→  const roofSystem = project.roofSystem && project.roofSystem.trussAttachmentId && !validTrussIds.has(project.roofSystem.trussAttachmentId)
555→    ? {
556→        ...project.roofSystem,
557→        trussAttachmentId: null,
558→      }
559→    : project.roofSystem;
560→
561→  return {
562→    ...project,
563→    version: Math.max(CURRENT_PROJECT_VERSION, Number(project.version || 0)),
564→    roofSystem,
565→    trussSystems: normalizedTrussSystems,
566→  };
567→}
