569→export function getAllTrussInstances(project, floorId = null) {
570→  return getProjectTrussSystems(project, floorId).flatMap((trussSystem) => (
571→    (trussSystem.trussInstances || []).map((trussInstance) => ({ trussSystem, trussInstance }))
572→  ));
573→}
