204→export function roofPitchDirectionFromAngle(angleDegrees = 90) {
205→  const radians = (Number(angleDegrees || 0) * Math.PI) / 180;
206→  return normalizeRoofPitchDirection({
207→    x: Math.cos(radians),
208→    y: Math.sin(radians),
