222→    ridgeOffset: isFiniteNumber(options.ridgeOffset) ? options.ridgeOffset : ROOF_RIDGE_OFFSET,
223→    overhang: isFiniteNumber(options.overhang) ? options.overhang : ROOF_OVERHANG,
