227→function createDefaultBoundary() {
228→  return [
229→    { x: -3000, y: -3000 },
230→    { x: 3000, y: -3000 },
231→    { x: 3000, y: 3000 },
232→    { x: -3000, y: 3000 },
233→  ];
234→}
