306→export function resolveRoofSectionCut(project, preferredFloorId = null, sectionCutId = null) {
307→  const floor = resolveRoofSectionFloor(project, preferredFloorId);
308→  if (!floor) return { floor: null, sectionCut: null };
309→
310→  const cuts = floor.sectionCuts || [];
311→  const sectionCut = sectionCutId
312→    ? cuts.find((entry) => entry.id === sectionCutId)
313→    : (cuts[0] || null);
314→
315→  return { floor, sectionCut };
316→}
