 9→export function isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode) {
10→  if (obj.phaseId) {
11→    const objPhase = phases.find(p => p.id === obj.phaseId);
12→    if (objPhase && objPhase.visible === false) return false;
13→  }
14→  if (phaseViewMode === PHASE_VIEW.ALL) return true;
15→  if (!obj.phaseId) return true;
16→  if (!activePhaseId) return true;
17→
18→  if (phaseViewMode === PHASE_VIEW.SINGLE) {
19→    return obj.phaseId === activePhaseId;
20→  }
21→
22→  if (phaseViewMode === PHASE_VIEW.CUMULATIVE) {
23→    const activePhase = phases.find(p => p.id === activePhaseId);
24→    const objPhase = phases.find(p => p.id === obj.phaseId);
25→    if (!activePhase || !objPhase) return true;
26→    return objPhase.order <= activePhase.order;
27→  }
28→
29→  return true;
30→}
