18→export function countObjectsInProjectPhase(project, phaseId) {
19→  let count = 0;
20→
21→  for (const floor of project.floors || []) {
22→    for (const key of PHASE_ASSIGNABLE_KEYS) {
23→      for (const obj of floor[key] || []) {
24→        if (obj.phaseId === phaseId) count++;
25→      }
26→    }
27→  }
28→
29→  if (project?.roofSystem?.phaseId === phaseId) {
30→    count += 1;
31→  }
32→  for (const trussSystem of project?.trussSystems || []) {
33→    if (trussSystem.phaseId === phaseId) count += 1;
34→  }
35→
36→  return count;
37→}
