343→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
344→    sheet.titleBlock = {
345→      projectTitleOverride: sheet.titleBlock?.projectTitleOverride ?? '',
346→      projectAddressOverride: sheet.titleBlock?.projectAddressOverride ?? '',
347→      drawnBy: sheet.titleBlock?.drawnBy ?? '',
348→      checkedBy: sheet.titleBlock?.checkedBy ?? '',
349→    };
350→    if (!Array.isArray(sheet.revisions)) sheet.revisions = [];
351→    sheet.revisions = sheet.revisions.map((revision) => ({
352→      ...createSheetRevision(),
353→      ...revision,
354→      id: revision?.id || `revision_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`,
355→    }));
356→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
357→
358→    for (const viewport of sheet.viewports) {
359→      if (!viewport.id) {
360→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
361→      }
362→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
363→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = getDefaultActiveFloorId(project);
364→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
365→      if (viewport.x === undefined) viewport.x = 20;
366→      if (viewport.y === undefined) viewport.y = 20;
367→      if (viewport.width === undefined) viewport.width = 160;
368→      if (viewport.height === undefined) viewport.height = 100;
369→      if (viewport.scale === undefined) viewport.scale = 100;
370→      if (viewport.title === undefined) viewport.title = '';
371→      if (viewport.rotation === undefined) viewport.rotation = 0;
372→      if (viewport.role === undefined) viewport.role = viewport.sourceView === '3d_preview'
373→        ? 'supplemental'
374→        : ((viewport.sourceView === 'plan' || viewport.sourceView === 'roof_plan' || viewport.sourceView === 'roof_drainage' || viewport.sourceView === 'truss_plan')
375→          ? 'primary'
376→          : (viewport.sourceView === 'truss_detail' ? 'detail' : 'secondary'));
377→      if (viewport.captionPosition === undefined) viewport.captionPosition = 'below';
378→      if (viewport.referenceNote === undefined) viewport.referenceNote = '';
379→      if (viewport.lockAutoLayout === undefined) viewport.lockAutoLayout = false;
380→      if (viewport.phaseId === undefined) viewport.phaseId = null;
381→      if (viewport.phaseViewMode === undefined) viewport.phaseViewMode = 'all';
382→    }
383→  }
384→
385→  project.phases = normalizePhases(project.phases || []);
386→  const validPhaseIds = new Set(project.phases.map((phase) => phase.id));
387→
388→  return {
389→    project: sanitizeProjectPhaseReferences(project, validPhaseIds),
390→    savedAt: json.savedAt,
391→  };
392→}
