 72→function normalizeRoofPitchSource(pitchSource = null, trussAttachmentId = null) {
 73→  if (pitchSource === 'manual') return 'manual';
 74→  if (pitchSource === 'truss') return 'truss';
 75→  return normalizeTrussAttachmentId(trussAttachmentId) ? 'truss' : 'manual';
