212→export function roofPitchDirectionToAngle(direction = null) {
213→  const normalized = normalizeRoofPitchDirection(direction);
214→  const degrees = (Math.atan2(normalized.y, normalized.x) * 180) / Math.PI;
215→  return ((degrees % 360) + 360) % 360;
