261→function largestFloorSlabBoundary(floor) {
262→  const slabs = (floor?.slabs || []).filter((slab) => polygonArea(slab.boundaryPoints || []) > 0);
263→  if (!slabs.length) return null;
264→
265→  const slab = [...slabs].sort((a, b) => polygonArea(b.boundaryPoints || []) - polygonArea(a.boundaryPoints || []))[0];
266→  return clonePoints(slab.boundaryPoints || []);
267→}
