288→export function resolveRoofSectionFloor(project, preferredFloorId = null) {
289→  const orderedFloors = getOrderedFloors(project);
290→  if (!orderedFloors.length) return null;
291→
292→  const preferredFloor = preferredFloorId
293→    ? orderedFloors.find((floor) => floor.id === preferredFloorId)
294→    : null;
295→  if (preferredFloor && (preferredFloor.sectionCuts || []).length) return preferredFloor;
296→
297→  for (let index = orderedFloors.length - 1; index >= 0; index -= 1) {
298→    if ((orderedFloors[index].sectionCuts || []).length) {
299→      return orderedFloors[index];
300→    }
301→  }
302→
303→  return preferredFloor || orderedFloors[orderedFloors.length - 1] || orderedFloors[0];
304→}
