504→function normalizeRelationships(collection = [], createFactory) {
505→  return (collection || []).map((entry) => {
506→    const normalized = createFactory(entry);
507→    return {
508→      ...normalized,
509→      ...entry,
510→      id: entry?.id || normalized.id,
511→      startPoint: clonePoint(entry?.startPoint),
512→      endPoint: clonePoint(entry?.endPoint),
513→      planeIds: [...new Set(entry?.planeIds || [])],
514→    };
