518→function normalizeRoofSystemCollections(roofSystem) {
519→  const roofType = normalizeRoofType(roofSystem.roofType);
520→  const boundaryPolygon = clonePoints(roofSystem.boundaryPolygon || createDefaultBoundary());
521→  const roofPlanes = normalizeRoofPlanes(
522→    roofSystem.roofPlanes || [],
523→    roofType,
524→    boundaryPolygon,
525→    roofSystem.baseElevation ?? 0
526→  );
527→
528→  if (roofType !== 'custom') {
529→    return {
530→      roofType,
531→      roofPlanes,
532→      roofEdges: normalizeRoofEdges(roofSystem.roofEdges || []),
533→      ridges: normalizeRelationships(roofSystem.ridges || [], createRidge),
534→      valleys: normalizeRelationships(roofSystem.valleys || [], createValley),
535→      hips: normalizeRelationships(roofSystem.hips || [], createHip),
536→    };
537→  }
538→
539→  const topology = deriveCustomRoofTopology({
540→    ...roofSystem,
541→    roofType,
542→    boundaryPolygon,
543→    roofPlanes,
544→    roofEdges: normalizeRoofEdges(roofSystem.roofEdges || []),
545→  });
546→
547→  return {
548→    roofType,
549→    roofPlanes: topology.roofPlanes.map((plane) => ({
550→      ...createRoofPlane(plane.boundaryPoints, plane),
551→      ...plane,
552→      boundaryPoints: clonePoints(plane.boundaryPoints || []),
553→      slopeDirection: normalizeRoofPitchDirection(plane.slopeDirection),
554→    })),
555→    roofEdges: topology.roofEdges.map((edge) => ({
556→      ...createRoofEdge(edge.startPoint, edge.endPoint, edge),
557→      ...edge,
558→      startPoint: clonePoint(edge.startPoint),
559→      endPoint: clonePoint(edge.endPoint),
560→      planeIds: [...new Set(edge.planeIds || [])],
561→      edgeRole: normalizeRoofEdgeRole(edge.edgeRole),
562→    })),
563→    ridges: topology.ridges.map((ridge) => ({
564→      ...createRidge(ridge),
565→      ...ridge,
566→      startPoint: clonePoint(ridge.startPoint),
567→      endPoint: clonePoint(ridge.endPoint),
568→      planeIds: [...new Set(ridge.planeIds || [])],
569→    })),
570→    valleys: topology.valleys.map((valley) => ({
571→      ...createValley(valley),
572→      ...valley,
573→      startPoint: clonePoint(valley.startPoint),
574→      endPoint: clonePoint(valley.endPoint),
575→      planeIds: [...new Set(valley.planeIds || [])],
576→    })),
577→    hips: topology.hips.map((hip) => ({
578→      ...createHip(hip),
579→      ...hip,
580→      startPoint: clonePoint(hip.startPoint),
581→      endPoint: clonePoint(hip.endPoint),
582→      planeIds: [...new Set(hip.planeIds || [])],
583→    })),
