import { CURRENT_SCHEMA_VERSION } from '@/domain/projectVersion';
import { runMigrations } from './migrations/index';
import { validateProjectStructure, validateProjectReferences, repairBrokenReferences } from './validate';
import { UnsupportedVersionError, CorruptedDataError, ProjectValidationError } from './errors';

// Import all migration modules (side-effect: they self-register)
import './migrations/migration_14_to_15';

function detectSchemaVersion(json) {
  if (typeof json.schemaVersion === 'number' && json.schemaVersion > 0) {
    return json.schemaVersion;
  }
  if (typeof json.version === 'number' && json.version > 0) {
    return json.version; // legacy files
  }
  return null;
}

export function deserializeProject(json) {
  // 1. Basic envelope validation
  if (!json || typeof json !== 'object') {
    throw new CorruptedDataError('Input is not a valid object');
  }

  const detectedVersion = detectSchemaVersion(json);
  if (detectedVersion === null || !isSupportedSchemaVersion(detectedVersion)) {
    throw new UnsupportedVersionError(detectedVersion);
  }

  if (!json.data || typeof json.data !== 'object') {
    throw new CorruptedDataError('Missing project data envelope');
  }

  let project = json.data;

  // 2. Minimal pre-migration validation (must have id, name, floors)
  if (!project.id || !project.name || !Array.isArray(project.floors)) {
    throw new CorruptedDataError('Invalid project structure: missing id, name, or floors');
  }

  // 3. Run migration pipeline
  if (detectedVersion < CURRENT_SCHEMA_VERSION) {
    project = runMigrations(project, detectedVersion, CURRENT_SCHEMA_VERSION);
  }

  // 4. Structural validation
  const structuralErrors = validateProjectStructure(project);
  if (structuralErrors.length > 0) {
    throw new ProjectValidationError(structuralErrors);
  }

  // 5. Referential integrity check + auto-repair
  const refWarnings = validateProjectReferences(project);
  if (refWarnings.length > 0) {
    console.warn('[persistence] Reference warnings:', refWarnings);
    project = repairBrokenReferences(project);
  }

  return {
    project,
    savedAt: json.savedAt,
  };
}
```

