### 4. Validation Layer Design

**`src/persistence/validate.js`:**

The validation layer runs AFTER migrations, before the project enters the app. It serves as a safety net: if a migration has a bug, or if a user hand-edits a JSON file, validation catches structural problems before they cause runtime crashes in renderers or the reducer.

**Three levels of validation:**

**Level 1 -- Structural validation (required fields and types):**
```js
export function validateProjectStructure(project) {
  const errors = [];

  if (!project.id || typeof project.id !== 'string') 
    errors.push({ path: 'project.id', message: 'Missing or invalid project ID' });
  if (!project.name || typeof project.name !== 'string') 
    errors.push({ path: 'project.name', message: 'Missing or invalid project name' });
  if (!Array.isArray(project.floors) || project.floors.length === 0)
    errors.push({ path: 'project.floors', message: 'Project must have at least one floor' });

  for (let i = 0; i < (project.floors || []).length; i++) {
    const floor = project.floors[i];
    errors.push(...validateFloorStructure(floor, `project.floors[${i}]`));
  }

  // Validate sheets, roofSystem, trussSystems, phases similarly
  return errors;
}
```

**Level 2 -- Referential integrity (cross-references between objects):**
```js
export function validateProjectReferences(project) {
  const warnings = [];
  const wallIds = new Set();
  const columnIds = new Set();
  const floorIds = new Set(project.floors.map(f => f.id));
  const phaseIds = new Set((project.phases || []).map(p => p.id));

  // Collect all wall/column IDs
  for (const floor of project.floors) {
    for (const wall of floor.walls) wallIds.add(wall.id);
    for (const col of floor.columns) columnIds.add(col.id);
  }

  // Check door/window wallId references
  for (const floor of project.floors) {
    for (const door of floor.doors) {
      if (!wallIds.has(door.wallId))
        warnings.push({ path: `door:${door.id}`, message: `References non-existent wall ${door.wallId}` });
    }
    // ... windows, beam column refs, stair floor refs, etc.
  }

  return warnings;
}
```

**Level 3 -- Value range validation (numeric bounds, enum membership):**
```js
export function validateProjectValues(project) {
  const warnings = [];
  for (const floor of project.floors) {
    for (const wall of floor.walls) {
      if (wall.thickness <= 0 || wall.thickness > 2000)
        warnings.push({ path: `wall:${wall.id}.thickness`, message: `Unusual thickness: ${wall.thickness}` });
    }
    // ... similar for heights, dimensions, etc.
  }
  return warnings;
}
```

**Validation result handling:**
- Level 1 errors (structural) are FATAL: `deserializeProject` throws a descriptive `ProjectValidationError`
- Level 2 warnings (references) are logged to console but do NOT prevent loading. Broken references are auto-repaired (orphan doors removed, invalid phaseIds set to null -- the existing `sanitizeProjectPhaseReferences` is one example)
- Level 3 warnings (value ranges) are logged to console only. They are informational.

**`src/persistence/errors.js`:**
```js
export class PersistenceError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'PersistenceError';
    this.code = code;
  }
}

export class ProjectValidationError extends PersistenceError {
  constructor(errors) {
    super(`Project validation failed: ${errors.map(e => e.message).join('; ')}`);
    this.name = 'ProjectValidationError';
    this.code = 'VALIDATION_FAILED';
    this.errors = errors;
  }
}

export class UnsupportedVersionError extends PersistenceError {
  constructor(version) {
    super(`Unsupported schema version: ${version}`);
    this.name = 'UnsupportedVersionError';
    this.code = 'UNSUPPORTED_VERSION';
    this.version = version;
  }
}

export class CorruptedDataError extends PersistenceError {
  constructor(message) {
    super(message || 'Project data is corrupted');
    this.name = 'CorruptedDataError';
    this.code = 'CORRUPTED_DATA';
  }
}
```

